<template>
    <div class="simple-node">
      <div
        class="folder-name"
        @click="toggle"
        @contextmenu.prevent.stop="showContextMenu($event)"
        :class="{ selected: isSelected }"
      >
        <v-icon>{{ isExpanded ? 'mdi-folder-open' : 'mdi-folder' }}</v-icon>
        {{ folder.name }}
      </div>
  
      <!-- Context Menu -->
      <ContextMenu
        v-model:show="isMenuVisible"
        :options="optionsComponent"
      >
        <ContextMenuItem label="Create Subfolder" @click="handleMenuAction('create')" />
        <ContextMenuItem label="Rename Folder" @click="handleMenuAction('rename')" />
        <ContextMenuItem label="Delete Folder" @click="handleMenuAction('delete')" />
      </ContextMenu>
  
      <div v-if="isExpanded && folder.children.length" class="children">
        <SimpleNode
        v-for="child in folder.children"
        :key="child._id"
        :folder="child"
        :selected-folder-path="selectedFolderPath"
        @fetch-files="$emit('fetch-files', $event)"
        @select-folder="selectFolder"
        @toggle-folder="$emit('toggle-folder', $event)"
        @create-folder="createSubFolder"
        @rename-folder="renameFolder"
        @delete-folder="deleteFolder"
        />


      </div>
    </div>
  </template>
  
  <script>
  import { ContextMenu, ContextMenuItem } from '@imengyu/vue3-context-menu';  // Import components

  
  export default {
    name: 'SimpleNode',
    components: {
      ContextMenu,
      ContextMenuItem,
    },
    props: {
      folder: {
        type: Object,
        required: true,
      },
      selectedFolderPath: {
        type: String,
        required: true,
      },
    },
    data() {
        return {
        isMenuVisible: false,
        optionsComponent: {
            x: 0,
            y: 0,
            zIndex: 9999,
        },
        };
    },
    computed: {
        isSelected() {
        return this.folder.path === this.selectedFolderPath;
        },
        isExpanded() {
        return this.folder.isExpanded;
        },
    },
    methods: {
        toggle() {
            console.log('Toggle clicked for folder:', this.folder.path); // Add console log for debugging
            this.$emit('toggle-folder', this.folder.path);
            this.$emit('select-folder', this.folder.path);
        },

      selectFolder(path) {
        this.$emit('select-folder', path);
      },
      showContextMenu(event) {
        event.preventDefault();
        event.stopPropagation();
        console.log('Event:', event);
        console.log('ClientX:', event.clientX, 'ClientY:', event.clientY);
        this.optionsComponent.x = event.clientX;
        this.optionsComponent.y = event.clientY;
        this.isMenuVisible = true;
      },
      handleMenuAction(action) {
        const folderPath = this.folder.path; // Ensure the correct folder path is used
        switch (action) {
            case 'rename':
            this.renameFolder(folderPath);
            break;
            case 'delete':
            this.deleteFolder(folderPath);
            break;
            case 'create':
            this.$emit('create-folder', folderPath);
            break;
            default:
            break;
        }
        this.isMenuVisible = false;
        },
      renameFolder() {
        const newName = prompt('Enter the new name for the folder:', this.folder.name);
        if (newName && newName.trim() !== '') {
          this.$emit('rename-folder', this.folder.path, newName.trim());
        }
      },
      deleteFolder(path) {
        this.$emit('delete-folder', path);
        },
      createSubFolder(parentPath) {
        this.$emit('create-folder', parentPath);
      },
    },
  };
  </script>
  
  <style scoped>
  .simple-node {
    margin-left: 20px;
  }
  
  .folder-name {
    cursor: pointer;
    display: flex;
    align-items: center;
    padding: 5px; /* Add some padding for better click area */
    border-radius: 4px; /* Rounded corners */
    transition: background-color 0.3s ease; /* Smooth transition */
  }
  
  .folder-name:hover {
    background-color: #f0f0f0; /* Light grey on hover */
  }
  
  .selected {
    background-color: #e0f7fa; /* Light blue for selected folder */
  }
  
  .children {
    margin-left: 20px;
  }
  
  /* Styles for custom context menu (if needed) */
  .custom-context-menu {
    position: absolute;
    background-color: white;
    border: 1px solid #ccc;
    box-shadow: 2px 2px 5px rgba(0, 0, 0, 0.2);
    z-index: 1000;
    width: 150px;
    border-radius: 4px;
  }
  
  .custom-context-menu ul {
    list-style: none;
    margin: 0;
    padding: 5px 0;
  }
  
  .custom-context-menu li {
    padding: 8px 12px;
    cursor: pointer;
  }
  
  .custom-context-menu li:hover {
    background-color: #f0f0f0;
  }
  </style>
  